mapper.select:
SELECT p.*, vnd.vendor_nm AS vendor_nm, ste.site_nm AS site_nm, cd_pmc.code_label AS pay_method_cd_nm, cd_sps.code_label AS pay_status_cd_nm FROM st_settle_pay p LEFT JOIN sy_vendor vnd ON vnd.vendor_id = p.vendor_id LEFT JOIN sy_site ste ON ste.site_id = p.site_id LEFT JOIN sy_code cd_pmc ON cd_pmc.code_grp = 'PAY_METHOD_CD' AND cd_pmc.code_value = p.pay_method_cd LEFT JOIN sy_code cd_sps ON cd_sps.code_grp = 'SETTLE_PAY_STATUS' AND cd_sps.code_value = p.pay_status_cd
ORDER BY p.settle_pay_id ASC ORDER BY p.settle_pay_id DESC ORDER BY p.bank_nm ASC ORDER BY p.bank_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT p.*, vnd.vendor_nm AS vendor_nm, ste.site_nm AS site_nm, cd_pmc.code_label AS pay_method_cd_nm, cd_sps.code_label AS pay_status_cd_nm FROM st_settle_pay p LEFT JOIN sy_vendor vnd ON vnd.vendor_id = p.vendor_id LEFT JOIN sy_site ste ON ste.site_id = p.site_id LEFT JOIN sy_code cd_pmc ON cd_pmc.code_grp = 'PAY_METHOD_CD' AND cd_pmc.code_value = p.pay_method_cd LEFT JOIN sy_code cd_sps ON cd_sps.code_grp = 'SETTLE_PAY_STATUS' AND cd_sps.code_value = p.pay_status_cd
ORDER BY p.settle_pay_id ASC ORDER BY p.settle_pay_id DESC ORDER BY p.bank_nm ASC ORDER BY p.bank_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

