UPDATE st_settle_pay
settle_id = #{settleId}, site_id = #{siteId}, vendor_id = #{vendorId}, pay_amt = #{payAmt}, pay_method_cd = #{payMethodCd}, bank_nm = #{bankNm}, bank_account = #{bankAccount}, bank_holder = #{bankHolder}, pay_status_cd = #{payStatusCd}, pay_status_cd_before = #{payStatusCdBefore}, pay_date = #{payDate}, pay_by = #{payBy}, settle_pay_memo = #{settlePayMemo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE settle_pay_id = #{settlePayId}
